usp.enabled = true

	and ub.bsns_year = #{bsnsYear}


	and ub.bsns_nm like concat('%', #{bsnsNm}, '%')


	and usp.ntce = #{ntce}


	and ub.chrg_dept_nm like concat('%', #{chrgDeptNm}, '%')




			and usp.slctn_pblanc_nm like concat('%', #{keyword}, '%')

mapper.insert:
/** UsptSlctnPblancDao.insert */
insert into uspt_slctn_pblanc
					(
						slctn_pblanc_id
						, pblanc_id
						, rcept_odr

						, evl_step_id


						, sect_id


						, evl_last_slctn_id

						, slctn_pblanc_nm
						, slctn_pblanc_no
						, slctn_pblanc_day
						, slctn_pblanc_sumry
						, ntce
						, enabled
						, attachment_group_id
						, creator_id
						, created_dt
						, updater_id
						, updated_dt
					)
			values	(
						#{slctnPblancId}
						, #{pblancId}
						, #{rceptOdr}

						, #{evlStepId}


						, #{sectId}


						, #{evlLastSlctnId}

						, #{slctnPblancNm}
						, #{slctnPblancNo}
						, #{slctnPblancDay}
						, #{slctnPblancSumry}
						, #{ntce}
						, #{enabled}
						, #{attachmentGroupId}
						, #{creatorId}
						, #{createdDt}
						, #{updaterId}
						, #{updatedDt}
					)

mapper.update:
/** UsptSlctnPblancDao.update */
update uspt_slctn_pblanc
set
	slctn_pblanc_nm			= #{slctnPblancNm}
	, slctn_pblanc_no		= #{slctnPblancNo}
	, slctn_pblanc_day		= #{slctnPblancDay}
	, slctn_pblanc_sumry	= #{slctnPblancSumry}
	, attachment_group_id	= #{attachmentGroupId}
	, updater_id			= #{updaterId}
	, updated_dt			= #{updatedDt}
where
	slctn_pblanc_id = #{slctnPblancId}

/** UsptSlctnPblancDao.updateNtce */
update uspt_slctn_pblanc
set
	ntce		 = #{ntce}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	slctn_pblanc_id = #{slctnPblancId}

/** UsptSlctnPblancDao.updateUnable */
update uspt_slctn_pblanc
set
	enabled		 = false
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	slctn_pblanc_id = #{slctnPblancId}

mapper.select:
/** UsptSlctnPblancDao."selectFrontListCount" */ select count(sub.slctn_pblanc_id) from ( select usp.slctn_pblanc_id from uspt_slctn_pblanc usp inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = usp.pblanc_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id and ubpr.rcept_odr = usp.rcept_odr inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.pblanc_id = ubpr.pblanc_id and ubpa.rcept_odr = ubpr.rcept_odr inner join uspt_evl_trget uet on uet.evl_step_id = usp.evl_step_id and uet.sect_id = usp.sect_id and uet.apply_id = ubpa.apply_id and uet.slctn = true where usp.ntce = true and usp.enabled = true and ubpa.member_id = #{memberId}
and usp.slctn_pblanc_nm like concat('%', #{slctnPblancNm}, '%')
union all select usp.slctn_pblanc_id from uspt_slctn_pblanc usp inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = usp.pblanc_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id and ubpr.rcept_odr = usp.rcept_odr inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.pblanc_id = ubpr.pblanc_id and ubpa.rcept_odr = ubpr.rcept_odr inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = usp.evl_last_slctn_id and ulst.slctn = true where usp.ntce = true and usp.enabled = true and ubpa.member_id = #{memberId}
and usp.slctn_pblanc_nm like concat('%', #{slctnPblancNm}, '%')
) sub

/** UsptSlctnPblancDao.selectFrontList */ select main.* from ( select sub.* , lag(sub.slctn_pblanc_id, 1) over(order by sub.created_dt desc) as pre_slctn_pblanc_id , lag(sub.slctn_pblanc_nm, 1, '이전 선정결과공고가 없습니다.') over(order by sub.created_dt desc) as pre_slctn_pblanc_nm , lead (sub.slctn_pblanc_id, 1) over(order by sub.created_dt desc) as next_slctn_pblanc_id , lead (sub.slctn_pblanc_nm, 1, '다음 선정결과공고가 없습니다.') over(order by sub.created_dt desc) as next_slctn_pblanc_nm from ( select usp.slctn_pblanc_id , usp.slctn_pblanc_nm , usp.slctn_pblanc_sumry , ubp.pblanc_nm , usp.created_dt , case when cast(to_char(now() , 'YYYYMMDDHH24MISS') as bigint) - cast(to_char(usp.created_dt , 'YYYYMMDDHH24MISS') as bigint) <= 240000 then 'Y' else 'N' end as is_new , ubpa.member_id from uspt_slctn_pblanc usp inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = usp.pblanc_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id and ubpr.rcept_odr = usp.rcept_odr inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.pblanc_id = ubpr.pblanc_id and ubpa.rcept_odr = ubpr.rcept_odr inner join uspt_evl_trget uet on uet.evl_step_id = usp.evl_step_id and uet.sect_id = usp.sect_id and uet.apply_id = ubpa.apply_id where usp.ntce = true and usp.enabled = true and ubpa.member_id = #{memberId}
and usp.slctn_pblanc_nm like concat('%', #{slctnPblancNm}, '%')
union all select usp.slctn_pblanc_id , usp.slctn_pblanc_nm , usp.slctn_pblanc_sumry , ubp.pblanc_nm , usp.created_dt , case when cast(to_char(now() , 'YYYYMMDDHH24MISS') as bigint) - cast(to_char(usp.created_dt , 'YYYYMMDDHH24MISS') as bigint) <= 240000 then 'Y' else 'N' end as is_new , ubpa.member_id from uspt_slctn_pblanc usp inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = usp.pblanc_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id and ubpr.rcept_odr = usp.rcept_odr inner join uspt_bsns_pblanc_applcnt ubpa on ubpa.pblanc_id = ubpr.pblanc_id and ubpa.rcept_odr = ubpr.rcept_odr inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = usp.evl_last_slctn_id where usp.ntce = true and usp.enabled = true and ubpa.member_id = #{memberId}
and usp.slctn_pblanc_nm like concat('%', #{slctnPblancNm}, '%')
) sub order by sub.created_dt desc
offset #{beginRowNum} -1 limit #{itemsPerPage}
) main
main.slctn_pblanc_id = #{slctnPblancId}
